def solve(n: int, edges: list[list[int]], k: int) -> int:
    if not edges:
        return 0
    max_time = max(edge[2] for edge in edges)
    low = 0
    high = max_time
    answer = max_time

    def count_components(t):
        parent = list(range(n))

        def find(u):
            while parent[u] != u:
                parent[u] = parent[parent[u]]
                u = parent[u]
            return u

        def union(u, v):
            root_u = find(u)
            root_v = find(v)
            if root_u != root_v:
                parent[root_v] = root_u

        for u, v, time in edges:
            if time > t:
                union(u, v)

        roots = set()
        for i in range(n):
            roots.add(find(i))
        return len(roots)

